import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/updating-fabric.1C0PZ95m.js";const o=JSON.parse(`{"title":"Fabric auf Linux aktualisieren","description":"Ein Schritt-für-Schritt-Leitfaden zur Aktualisierung von Fabric auf Linux.","frontmatter":{"title":"Fabric auf Linux aktualisieren","description":"Ein Schritt-für-Schritt-Leitfaden zur Aktualisierung von Fabric auf Linux.","authors":["IMB11","modmuss50"],"next":false,"files":[]},"headers":[],"relativePath":"de_de/players/updating-fabric/linux.md","filePath":"translated/de_de/players/updating-fabric/linux.md","lastUpdated":1770561656000}`);var s={name:`de_de/players/updating-fabric/linux.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Fabric auf Linux aktualisieren <a class="header-anchor" href="#h1" aria-label="Permalink to “Fabric auf Linux aktualisieren”">​</a></h1><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Den Fabric Installer herunterladen <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Den Fabric Installer herunterladen”">​</a></h2><p>Lade die <code>.jar</code> Version des Fabric Installer von der <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Fabric Website</a> herunter, indem du auf <code>Download installer (Universal/.JAR)</code> klickst.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Den Fabric Installer ausführen <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Den Fabric Installer ausführen”">​</a></h2><p>Schließe vor dem Ausführen des Installers zuerst Minecraft und den Minecraft Launcher.</p><p>Öffne ein Terminal und führe den Installer mit Java aus:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">java</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -jar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fabric-installer.jar</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Sobald du den Installer öffnest, solltest du eine Oberfläche wie diese sehen:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Fabric Installer mit &quot;Install&quot; hervorgehoben" loading="lazy"></p><p>Stelle sicher, dass die neue Spielversion und die Loader Version korrekt sind, und klicke dann auf <code>Installieren</code>, um Fabric zu aktualisieren.</p><div class="warning custom-block"><p class="custom-block-title">WICHTIG</p><p>Stelle sicher <code>Profil erstellen</code> abzuwählen, wenn du den Installer ausführst!</p></div><h2 id="3-update-launcher-profile" tabindex="-1">3. Das Profil im Minecraft Launcher aktualisieren <a class="header-anchor" href="#3-update-launcher-profile" aria-label="Permalink to “3. Das Profil im Minecraft Launcher aktualisieren”">​</a></h2><p>Sobald die Installation abgeschlossen ist, öffne den Minecraft Launcher. Dann wechsle zum <code>Installationen</code> Tab. Finde dein Fabric Profil und öffne dessen Bearbeitungsoberfläche:</p><p><img src="/assets/players/updating-fabric.png" alt="Aktualisieren der Fabric Loader Version im Minecraft Launcher" loading="lazy"></p><p>Ersetze die Version durch die neue Version von Fabric Loader, die du gerade installiert hast, und drücke <code>Speichern</code>.</p><h2 id="4-you-re-done" tabindex="-1">4. Du hast es geschafft! <a class="header-anchor" href="#4-you-re-done" aria-label="Permalink to “4. Du hast es geschafft!”">​</a></h2><p>Sobald du die Schritte abgeschlossen hast, kannst du zur Registerkarte <code>Spielen</code> zurückkehren, das Fabric-Profil aus dem Dropdown-Menü in der linken unteren Ecke auswählen und auf <code>Spielen</code> drücken!</p><p>Wenn du beim Befolgen dieses Leitfadens auf Probleme stößt, kannst du im <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> im Kanal <code>#player-support</code> um Hilfe bitten.</p>`,18)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};